#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int min(int a, int b) { return a < b ? a : b; }
int tree[4 * MAXN];
void build(int node, int start, int end, int arr[]) {
    if (start == end) {
        tree[node] = arr[start];
    } else {
        int mid = (start + end) / 2;
        build(2 * node, start, mid, arr);
        build(2 * node + 1, mid + 1, end, arr);
        tree[node] = min(tree[2 * node], tree[2 * node + 1]);
    }
}
int query(int node, int start, int end, int l, int r) {
    if (r < start || end < l) {
        return 1000000007;
    }
    if (l <= start && end <= r) {
        return tree[node];
    }
    int mid = (start + end) / 2;
    return min(query(2 * node, start, mid, l, r), query(2 * node + 1, mid + 1, end, l, r));
}
void update(int node, int start, int end, int l, int r, int x) {
    if (r < start || end < l) {
        return;
    }
    if (start == end) {
        tree[node] = tree[node] & x;
    } else {
        int mid = (start + end) / 2;
        update(2 * node, start, mid, l, r, x);
        update(2 * node + 1, mid + 1, end, l, r, x);
        tree[node] = min(tree[2 * node], tree[2 * node + 1]);
    }
}
int main() {
    int n, q;
    scanf("%d %d", &n, &q);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    build(1, 0, n - 1, arr);
    while (q--) {
        int type;
        scanf("%d", &type);
        if (type == 0) {
            int l, r;
            scanf("%d %d", &l, &r);
            printf("%d\n", query(1, 0, n - 1, l - 1, r - 1));
        } else {
            int l, r, x;
            scanf("%d %d %d", &l, &r, &x);
            update(1, 0, n - 1, l - 1, r - 1, x);
        }
    }
    return 0;
}

